+  private getCursorSort(
+    orderBy: Record<string, unknown> | Record<string, unknown>[],
+  ): { field: string; direction: 'asc' | 'desc' }[] {
+    const entries = (Array.isArray(orderBy) ? orderBy : [orderBy]).flatMap(
+      (part) => Object.entries(part),
+    );
+    const sort = entries.map(([field, direction]) => ({
+      field,
+      direction: this.normalizeCursorDirection(direction),
+    }));
+    const idField = this.crudConfig.id_field as string;
+    if (!sort.some(({ field }) => field === idField)) {
+      sort.push({ field: idField, direction: 'asc' });
+    }
+    return sort;
+  }
+
+  private normalizeCursorDirection(direction: unknown): 'asc' | 'desc' {
+    const normalized = String(direction).toLowerCase();
+    if (normalized === 'asc' || normalized === '1') return 'asc';
+    if (normalized === 'desc' || normalized === '-1') return 'desc';
+    throw new BadRequestException('orderBy must use asc or desc with cursor pagination');
+  }
+
+  private getCursorCondition(
+    encodedCursor: string,
+    sort: { field: string; direction: 'asc' | 'desc' }[] | undefined,
+  ) {
+    if (!sort) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    let cursor: Record<string, unknown>;
+    try {
+      if (!/^[A-Za-z0-9+/]*={0,2}$/.test(encodedCursor) || encodedCursor.length % 4 !== 0) {
+        throw new Error('Invalid Base64');
+      }
+      cursor = JSON.parse(Buffer.from(encodedCursor, 'base64').toString('utf8'));
+    } catch {
+      throw new BadRequestException('cursor must be valid Base64-encoded JSON');
+    }
+    if (!cursor || Array.isArray(cursor) || typeof cursor !== 'object') {
+      throw new BadRequestException('cursor must be valid Base64-encoded JSON');
+    }
+
+    const expectedSort = sort.map(({ field, direction }) => `${field}:${direction}`).join(',');
+    if (cursor.__sort !== expectedSort) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+    const idField = this.crudConfig.id_field as string;
+    if (!(idField in cursor)) {
+      throw new BadRequestException(`cursor is missing ${idField}`);
+    }
+    for (const { field } of sort) {
+      if (!(field in cursor)) {
+        throw new BadRequestException(`cursor is missing ${field}`);
+      }
+    }
+
+    return {
+      $or: sort.map(({ field, direction }, index) => ({
+        $and: [
+          ...sort.slice(0, index).map(({ field }) => ({ [field]: cursor[field] })),
+          { [field]: { [direction === 'asc' ? '$gt' : '$lt']: cursor[field] } },
+        ],
+      })),
+    };
+  }
+
+  private createCursor(
+    entity: T,
+    sort: { field: string; direction: 'asc' | 'desc' }[],
+  ): string {
+    const cursor: Record<string, unknown> = {
+      __sort: sort.map(({ field, direction }) => `${field}:${direction}`).join(','),
+    };
+    for (const { field } of sort) {
+      cursor[field] = entity[field];
+    }
+    return Buffer.from(JSON.stringify(cursor)).toString('base64');
+  }
