  @IsArray()
  @IsString({ each: true })
  @$MaxSize(300)
  fields?: Extract<keyof T, string>[];

  @IsOptional()
  @IsArray()
  @IsString({ each: true })
  @$MaxSize(300)
  exclude?: Extract<keyof T, string>[];

  @IsOptional()
  @IsInt()
